mapper.update:
UPDATE employee
SET employee_name = #{employeeName},
    gender        = #{employeeGender},
    age           = #{employeeAge},
    position      = #{staff}
WHERE employee_no = #{employeeAccount}

mapper.select:
SELECT employee_no AS employee_account, employee_name, gender AS employee_gender, age AS employee_age, entry_date AS entry_time, position AS staff, '' AS employee_message FROM employee
AND ( employee_no LIKE CONCAT('%', #{keyword}, '%') OR employee_name LIKE CONCAT('%', #{keyword}, '%') )
AND gender = #{gender}
AND position LIKE CONCAT('%', #{staff}, '%')
ORDER BY employee_no ASC LIMIT #{offset}, #{pageSize}
